package docprose

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

// TempValeConfig holds paths to a temporary Vale configuration scoped to one invocation.
type TempValeConfig struct {
	dir     string
	iniPath string
}

// INIPath returns the path to the generated .vale.ini file.
func (t *TempValeConfig) INIPath() string {
	return t.iniPath
}

// StylesPath returns the absolute styles directory written into the generated .vale.ini.
func (t *TempValeConfig) StylesPath() string {
	return filepath.Join(t.dir, "styles")
}

// Cleanup removes all temporary files created for this config.
func (t *TempValeConfig) Cleanup() {
	os.RemoveAll(t.dir)
}

// NewTempValeConfig generates a temporary Vale configuration from DDx settings.
// StylesPath is pointed at the packaged DDx styles via a symlink so no copy is needed.
// Project vocabulary is rendered into Vale accept/reject files under Vocab/Project/.
// The caller must call Cleanup() when done.
func NewTempValeConfig(settings Settings) (*TempValeConfig, error) {
	assetRoot, err := defaultAssetRoot()
	if err != nil {
		return nil, fmt.Errorf("resolve asset root: %w", err)
	}
	packagedDDxStyles := filepath.Join(assetRoot, "styles", "DDx")

	dir, err := os.MkdirTemp("", "ddx-vale-")
	if err != nil {
		return nil, fmt.Errorf("create temp vale dir: %w", err)
	}

	stylesDir := filepath.Join(dir, "styles")
	if err := os.MkdirAll(stylesDir, 0o755); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("create styles dir: %w", err)
	}

	// Symlink the packaged DDx style directory so we avoid copying rule files.
	if err := os.Symlink(packagedDDxStyles, filepath.Join(stylesDir, "DDx")); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("symlink DDx styles: %w", err)
	}

	vocabName := ""
	if len(settings.Vocabulary.Accept) > 0 || len(settings.Vocabulary.Reject) > 0 {
		vocabName = "Project"
		vocabDir := filepath.Join(stylesDir, "Vocab", vocabName)
		if err := os.MkdirAll(vocabDir, 0o755); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("create vocab dir: %w", err)
		}
		if err := writeTextLines(filepath.Join(vocabDir, "accept.txt"), settings.Vocabulary.Accept); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("write accept vocabulary: %w", err)
		}
		if err := writeTextLines(filepath.Join(vocabDir, "reject.txt"), settings.Vocabulary.Reject); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("write reject vocabulary: %w", err)
		}
	}

	style := settings.Vale.Style
	if style == "" {
		style = "DDx"
	}

	iniPath := filepath.Join(dir, ".vale.ini")
	ini := buildValeINI(stylesDir, style, vocabName)
	if err := os.WriteFile(iniPath, []byte(ini), 0o644); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("write .vale.ini: %w", err)
	}

	return &TempValeConfig{dir: dir, iniPath: iniPath}, nil
}

func buildValeINI(stylesPath, style, vocabName string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "StylesPath = %s\n", stylesPath)
	fmt.Fprintf(&b, "MinAlertLevel = suggestion\n")
	if vocabName != "" {
		fmt.Fprintf(&b, "Vocab = %s\n", vocabName)
	}
	fmt.Fprintf(&b, "\n[*.md]\n")
	fmt.Fprintf(&b, "BasedOnStyles = %s\n", style)
	return b.String()
}

func writeTextLines(path string, lines []string) error {
	content := strings.Join(lines, "\n")
	if len(lines) > 0 {
		content += "\n"
	}
	return os.WriteFile(path, []byte(content), 0o644)
}

package checks

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"sync"
)

// Run evaluates every check in `all` whose AppliesTo filter matches `ctx`,
// in parallel, and returns the collected results sorted by check name.
//
// Each applicable check is run as `sh -c <command>` with the documented
// environment variables injected. After execution, the runner reads the
// expected ${EvidenceDir}/${name}.json file and parses it into a Result.
//
// Failure modes that produce status=error:
//   - Non-zero process exit.
//   - Result file missing.
//   - Result file unparseable / unknown status value.
//
// Run returns an error only for setup failures (e.g. cannot create
// EvidenceDir). Per-check failures are reported as Result{Status:error}
// in the returned slice.
func Run(ctx context.Context, all []Check, ictx InvocationContext) ([]Result, error) {
	if err := os.MkdirAll(ictx.EvidenceDir, 0o755); err != nil {
		return nil, fmt.Errorf("checks: create evidence dir: %w", err)
	}

	var applicable []Check
	for _, c := range all {
		if c.Applies(ictx) {
			applicable = append(applicable, c)
		}
	}

	results := make([]Result, len(applicable))
	var wg sync.WaitGroup
	for i := range applicable {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			results[i] = runOne(ctx, applicable[i], ictx)
		}(i)
	}
	wg.Wait()

	sort.Slice(results, func(i, j int) bool { return results[i].Name < results[j].Name })
	return results, nil
}

func runOne(ctx context.Context, c Check, ictx InvocationContext) Result {
	resultPath := filepath.Join(ictx.EvidenceDir, c.Name+".json")
	// Best-effort cleanup of any stale result file from a prior run so a
	// check that crashes without writing one is correctly classified as
	// status=error rather than silently picking up the previous output.
	_ = os.Remove(resultPath)

	cmd := exec.CommandContext(ctx, "sh", "-c", c.Command)
	cmd.Dir = ictx.ProjectRoot
	cmd.Env = append(os.Environ(),
		"BEAD_ID="+ictx.BeadID,
		"DIFF_BASE="+ictx.DiffBase,
		"DIFF_HEAD="+ictx.DiffHead,
		"PROJECT_ROOT="+ictx.ProjectRoot,
		"EVIDENCE_DIR="+ictx.EvidenceDir,
		"RUN_ID="+ictx.AttemptID,
		"CHECK_NAME="+c.Name,
	)
	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	runErr := cmd.Run()
	exitCode := 0
	if runErr != nil {
		if ee, ok := runErr.(*exec.ExitError); ok {
			exitCode = ee.ExitCode()
		} else {
			return Result{
				Name:     c.Name,
				Status:   StatusError,
				Message:  fmt.Sprintf("check %q failed to start: %v", c.Name, runErr),
				ExitCode: -1,
				Stderr:   stderr.String(),
			}
		}
	}

	if runErr != nil {
		return Result{
			Name:     c.Name,
			Status:   StatusError,
			Message:  fmt.Sprintf("check %q exited %d: %s", c.Name, exitCode, trim(stderr.String())),
			ExitCode: exitCode,
			Stderr:   stderr.String(),
		}
	}

	data, readErr := os.ReadFile(resultPath)
	if readErr != nil {
		return Result{
			Name:     c.Name,
			Status:   StatusError,
			Message:  fmt.Sprintf("check %q produced no result file at %s", c.Name, resultPath),
			ExitCode: exitCode,
			Stderr:   stderr.String(),
		}
	}

	var parsed Result
	if err := json.Unmarshal(data, &parsed); err != nil {
		return Result{
			Name:     c.Name,
			Status:   StatusError,
			Message:  fmt.Sprintf("check %q wrote invalid JSON to %s: %v", c.Name, resultPath, err),
			ExitCode: exitCode,
			Stderr:   stderr.String(),
		}
	}
	parsed.Name = c.Name
	parsed.ExitCode = exitCode
	parsed.Stderr = stderr.String()
	switch parsed.Status {
	case StatusPass, StatusBlock, StatusError:
		// ok
	default:
		return Result{
			Name:     c.Name,
			Status:   StatusError,
			Message:  fmt.Sprintf("check %q returned unknown status %q", c.Name, parsed.Status),
			ExitCode: exitCode,
			Stderr:   stderr.String(),
		}
	}
	return parsed
}

func trim(s string) string {
	const max = 500
	if len(s) <= max {
		return s
	}
	return s[:max] + "…"
}

package docprose

import (
	"encoding/json"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"testing"
)

type fixtureCase struct {
	Name     string
	Mode     string
	Input    string
	Golden   string
	Findings []Finding
}

func loadFixtureCase(t *testing.T, root, mode, name string) fixtureCase {
	t.Helper()

	dir := filepath.Join(root, mode, name)
	inputPath := filepath.Join(dir, "input.md")
	goldenPath := filepath.Join(dir, "findings.golden.json")

	input, err := os.ReadFile(inputPath)
	if err != nil {
		t.Fatalf("read %s: %v", inputPath, err)
	}
	golden, err := os.ReadFile(goldenPath)
	if err != nil {
		t.Fatalf("read %s: %v", goldenPath, err)
	}
	var findings []Finding
	if err := json.Unmarshal(golden, &findings); err != nil {
		t.Fatalf("unmarshal %s: %v", goldenPath, err)
	}
	return fixtureCase{
		Name:     name,
		Mode:     mode,
		Input:    string(input),
		Golden:   strings.TrimSpace(string(golden)),
		Findings: findings,
	}
}

func listFixtureCases(t *testing.T, root string) []fixtureCase {
	t.Helper()

	modes, err := os.ReadDir(root)
	if err != nil {
		t.Fatalf("read fixture root %s: %v", root, err)
	}

	var cases []fixtureCase
	for _, modeEntry := range modes {
		if !modeEntry.IsDir() {
			continue
		}
		mode := modeEntry.Name()
		modeDir := filepath.Join(root, mode)
		names, err := os.ReadDir(modeDir)
		if err != nil {
			t.Fatalf("read mode dir %s: %v", modeDir, err)
		}
		for _, nameEntry := range names {
			if !nameEntry.IsDir() {
				continue
			}
			cases = append(cases, loadFixtureCase(t, root, mode, nameEntry.Name()))
		}
	}

	sort.Slice(cases, func(i, j int) bool {
		if cases[i].Mode == cases[j].Mode {
			return cases[i].Name < cases[j].Name
		}
		return cases[i].Mode < cases[j].Mode
	})
	return cases
}

func TestFixtures(t *testing.T) {
	const root = "testdata/fixtures"
	cases := listFixtureCases(t, root)
	if len(cases) == 0 {
		t.Fatal("expected at least one docprose fixture case")
	}

	seenModes := map[string]bool{}
	for _, tc := range cases {
		t.Run(tc.Mode+"/"+tc.Name, func(t *testing.T) {
			seenModes[tc.Mode] = true
			if strings.TrimSpace(tc.Input) == "" {
				t.Fatalf("fixture input is empty")
			}
			if !strings.Contains(tc.Input, "\n") {
				t.Fatalf("fixture input must be markdown with multiple lines")
			}
			if !strings.HasSuffix(tc.Golden, "]") {
				t.Fatalf("golden must be a JSON array: %s", tc.Golden)
			}

			checker, err := NewChecker(Mode(tc.Mode), Vocabulary{})
			if err != nil {
				t.Fatal(err)
			}
			got := checker.Findings("input.md", tc.Input)
			if !sameFindings(got, tc.Findings) {
				gotJSON, err := json.MarshalIndent(got, "", "  ")
				if err != nil {
					t.Fatalf("marshal got findings: %v", err)
				}
				t.Fatalf("fixture golden mismatch for %s/%s\n--- got ---\n%s\n--- want ---\n%s", tc.Mode, tc.Name, gotJSON, tc.Golden)
			}

			for i, finding := range got {
				if finding.File == "" || finding.Line == 0 || finding.RuleID == "" || finding.Severity == "" || finding.Rationale == "" || finding.SuggestedEdit == "" {
					t.Fatalf("finding %d missing required field: %+v", i, finding)
				}
			}
		})
	}

	for _, mode := range []string{"technical", "planning", "public"} {
		if !seenModes[mode] {
			t.Fatalf("expected at least one fixture in %q mode", mode)
		}
	}
}

package docprose

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

type corpusExpect struct {
	Mode          string   `json:"mode"`
	ExpectRuleIDs []string `json:"expect_rule_ids"`
}

type corpusCase struct {
	Group  string
	Name   string
	Input  string
	Expect corpusExpect
}

const corpusRoot = "testdata/corpus"

var requiredCorpusGroups = []string{
	"positive/ai-slop",
	"positive/unsupported-claim",
	"positive/token-cost",
	"positive/missing-actor-action",
	"negative/technical-density",
	"negative/markdown-structure",
	"negative/evidence-backed-claim",
	"real/ddx-docs",
}

func loadCorpusCases(t *testing.T) []corpusCase {
	t.Helper()
	var cases []corpusCase
	for _, group := range requiredCorpusGroups {
		groupDir := filepath.Join(corpusRoot, group)
		entries, err := os.ReadDir(groupDir)
		if err != nil {
			t.Fatalf("read corpus group %s: %v", group, err)
		}
		for _, entry := range entries {
			if !entry.IsDir() {
				continue
			}
			caseDir := filepath.Join(groupDir, entry.Name())
			inputPath := filepath.Join(caseDir, "input.md")
			expectPath := filepath.Join(caseDir, "expect.json")

			input, err := os.ReadFile(inputPath)
			if err != nil {
				t.Fatalf("read %s: %v", inputPath, err)
			}
			expectData, err := os.ReadFile(expectPath)
			if err != nil {
				t.Fatalf("read %s: %v", expectPath, err)
			}
			var expect corpusExpect
			if err := json.Unmarshal(expectData, &expect); err != nil {
				t.Fatalf("unmarshal %s: %v", expectPath, err)
			}
			cases = append(cases, corpusCase{
				Group:  group,
				Name:   entry.Name(),
				Input:  string(input),
				Expect: expect,
			})
		}
	}
	return cases
}

func TestDocProseCorpus_LoadsGroups(t *testing.T) {
	cases := loadCorpusCases(t)

	groupCounts := map[string]int{}
	for _, c := range cases {
		groupCounts[c.Group]++
	}

	for _, group := range requiredCorpusGroups {
		if groupCounts[group] == 0 {
			t.Errorf("corpus group %q has no cases", group)
		}
	}
	if t.Failed() {
		t.FailNow()
	}
	t.Logf("loaded %d corpus cases across %d groups", len(cases), len(groupCounts))
}

func TestDocProseCorpus_ExpectedFindingSchema(t *testing.T) {
	cases := loadCorpusCases(t)

	validModes := map[string]bool{
		"technical": true,
		"planning":  true,
		"public":    true,
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.Group+"/"+tc.Name, func(t *testing.T) {
			if !validModes[tc.Expect.Mode] {
				t.Errorf("expect.json mode %q is not valid (want technical/planning/public)", tc.Expect.Mode)
			}
			if tc.Expect.ExpectRuleIDs == nil {
				t.Errorf("expect.json missing expect_rule_ids field")
			}
			for _, rid := range tc.Expect.ExpectRuleIDs {
				if rid == "" {
					t.Errorf("expect.json contains empty rule_id")
				}
				if !strings.HasPrefix(rid, "prose.") {
					t.Errorf("expect.json rule_id %q must start with prose.", rid)
				}
			}
		})
	}
}

func TestDocProseCorpus_NegativeStructureCasesStayQuiet(t *testing.T) {
	const group = "negative/markdown-structure"
	groupDir := filepath.Join(corpusRoot, group)
	entries, err := os.ReadDir(groupDir)
	if err != nil {
		t.Fatalf("read %s: %v", groupDir, err)
	}

	seenCategories := map[string]bool{}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		caseDir := filepath.Join(groupDir, entry.Name())
		inputPath := filepath.Join(caseDir, "input.md")
		expectPath := filepath.Join(caseDir, "expect.json")

		input, err := os.ReadFile(inputPath)
		if err != nil {
			t.Fatalf("read %s: %v", inputPath, err)
		}
		expectData, err := os.ReadFile(expectPath)
		if err != nil {
			t.Fatalf("read %s: %v", expectPath, err)
		}
		var expect corpusExpect
		if err := json.Unmarshal(expectData, &expect); err != nil {
			t.Fatalf("unmarshal %s: %v", expectPath, err)
		}

		seenCategories[entry.Name()] = true
		name := entry.Name()

		t.Run(name, func(t *testing.T) {
			checker, err := NewChecker(Mode(expect.Mode), Vocabulary{})
			if err != nil {
				t.Fatal(err)
			}
			findings := checker.Findings("input.md", string(input))
			if len(findings) != 0 {
				data, _ := json.MarshalIndent(findings, "", "  ")
				t.Errorf("negative structure case %q produced %d finding(s), expected 0:\n%s",
					name, len(findings), data)
			}
		})
	}

	required := []string{"path", "command", "table", "code-span", "frontmatter", "id"}
	for _, cat := range required {
		found := false
		for name := range seenCategories {
			if strings.Contains(name, cat) {
				found = true
				break
			}
		}
		if !found {
			t.Errorf("negative/markdown-structure corpus missing a case covering category %q", cat)
		}
	}
}

func TestDocProseCorpus_PositiveCasesCanAssertRuleIDs(t *testing.T) {
	positiveGroups := []string{
		"positive/ai-slop",
		"positive/unsupported-claim",
		"positive/token-cost",
		"positive/missing-actor-action",
	}

	for _, group := range positiveGroups {
		groupDir := filepath.Join(corpusRoot, group)
		entries, err := os.ReadDir(groupDir)
		if err != nil {
			t.Fatalf("read %s: %v", groupDir, err)
		}

		for _, entry := range entries {
			if !entry.IsDir() {
				continue
			}
			caseDir := filepath.Join(groupDir, entry.Name())
			inputPath := filepath.Join(caseDir, "input.md")
			expectPath := filepath.Join(caseDir, "expect.json")

			input, err := os.ReadFile(inputPath)
			if err != nil {
				t.Fatalf("read %s: %v", inputPath, err)
			}
			expectData, err := os.ReadFile(expectPath)
			if err != nil {
				t.Fatalf("read %s: %v", expectPath, err)
			}
			var expect corpusExpect
			if err := json.Unmarshal(expectData, &expect); err != nil {
				t.Fatalf("unmarshal %s: %v", expectPath, err)
			}

			group, entryName := group, entry.Name()
			t.Run(group+"/"+entryName, func(t *testing.T) {
				if len(expect.ExpectRuleIDs) == 0 {
					t.Skipf("positive case %s/%s has no expected rule_ids (no assertion)", group, entryName)
				}

				checker, err := NewChecker(Mode(expect.Mode), Vocabulary{})
				if err != nil {
					t.Fatal(err)
				}
				findings := checker.Findings("input.md", string(input))

				actualRuleIDs := map[string]bool{}
				for _, f := range findings {
					actualRuleIDs[f.RuleID] = true
				}

				for _, expectedRuleID := range expect.ExpectRuleIDs {
					if !actualRuleIDs[expectedRuleID] {
						data, _ := json.MarshalIndent(findings, "", "  ")
						t.Errorf("expected rule_id %q not found in findings for %s/%s:\n%s",
							expectedRuleID, group, entryName, data)
					}
				}
			})
		}
	}
}

package docprose

import (
	"os"
	"path/filepath"
	"strings"
	"testing"

	ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"
)

func TestProseCheckerFindingSchema(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{})
	if err != nil {
		t.Fatal(err)
	}
	findings := checker.Findings("input.md", "This is robust.\n")
	if len(findings) == 0 {
		t.Fatal("expected at least one finding")
	}
	f := findings[0]
	if f.File != "input.md" || f.Line != 1 || f.RuleID == "" || f.Severity == "" || f.Rationale == "" || f.SuggestedEdit == "" {
		t.Fatalf("finding missing required field(s): %+v", f)
	}
}

func TestProseCheckerVocabularyOverrides(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{
		Accept: []string{"Quartz"},
		Reject: []string{"system", "solution"},
	})
	if err != nil {
		t.Fatal(err)
	}

	findings := checker.Findings("input.md", "Quartz keeps the system solution honest.\n")
	if len(findings) != 2 {
		t.Fatalf("expected 2 reject findings, got %+v", findings)
	}
	for _, finding := range findings {
		if finding.RuleID != "prose.vocabulary.reject" {
			t.Fatalf("unexpected rule id: %+v", finding)
		}
	}
}

func TestProseCheckerVocabularyPreservation(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{
		Accept: []string{"Quartz"},
		Reject: []string{"system"},
	})
	if err != nil {
		t.Fatal(err)
	}

	findings := checker.Findings("input.md", "Quartz keeps the system honest.\n")
	if len(findings) != 1 {
		t.Fatalf("expected one reject finding, got %+v", findings)
	}
	if findings[0].RuleID != "prose.vocabulary.reject" {
		t.Fatalf("unexpected rule id: %+v", findings[0])
	}
	if strings.Contains(findings[0].Rationale, "Quartz") {
		t.Fatalf("accepted term should not be flagged, got %+v", findings[0])
	}
}

func TestDefaultAssetLayout(t *testing.T) {
	root, err := defaultAssetRoot()
	if err != nil {
		t.Fatal(err)
	}
	for _, path := range []string{
		filepath.Join(root, "check.yaml"),
		filepath.Join(root, "rules", "technical.yaml"),
		filepath.Join(root, "rules", "planning.yaml"),
		filepath.Join(root, "rules", "public.yaml"),
		filepath.Join(root, "vocabulary", "default.yaml"),
	} {
		if _, err := os.Stat(path); err != nil {
			t.Fatalf("expected asset %s: %v", path, err)
		}
	}

	cfg, err := loadDefaultConfig()
	if err != nil {
		t.Fatal(err)
	}
	if cfg.Mode != string(ModeTechnical) || cfg.Policy != "advisory" || cfg.Runner != "embedded" {
		t.Fatalf("unexpected default config: %+v", cfg)
	}

	vocab, err := loadDefaultVocabulary()
	if err != nil {
		t.Fatal(err)
	}
	if !containsAll(vocab.Accept, []string{"DDx", "bead", "execution"}) {
		t.Fatalf("default accept vocabulary missing DDx terms: %+v", vocab.Accept)
	}
	if len(vocab.Reject) != 0 {
		t.Fatalf("default reject vocabulary should be empty; got %+v", vocab.Reject)
	}
}

func TestResolveSettingsLayersConfig(t *testing.T) {
	settings, err := ResolveSettings(&ddxconfig.Config{
		Prose: &ddxconfig.ProseConfig{
			Mode:     "planning",
			Severity: "warning",
			Policy:   "blocking",
			Runner:   "vale",
			Vocabulary: &ddxconfig.ProseVocabularyConfig{
				Accept: []string{"Quartz"},
				Reject: []string{"system"},
			},
		},
	})
	if err != nil {
		t.Fatal(err)
	}
	if settings.Mode != ModePlanning || settings.Severity != "warning" || settings.Policy != "blocking" || settings.Runner != "vale" {
		t.Fatalf("unexpected layered settings: %+v", settings)
	}
	if !containsAll(settings.Vocabulary.Accept, []string{"Quartz"}) || !containsAll(settings.Vocabulary.Reject, []string{"system"}) {
		t.Fatalf("expected layered vocabulary overrides: %+v", settings.Vocabulary)
	}
}

func TestProseCheckerChangedMode(t *testing.T) {
	cases := listFixtureCases(t, "testdata/fixtures")
	for _, tc := range cases {
		t.Run(tc.Mode+"/"+tc.Name, func(t *testing.T) {
			checker, err := NewChecker(Mode(tc.Mode), Vocabulary{})
			if err != nil {
